HttpRequest req = new HttpRequest();
req.setEndpoint('callout:Stripe/v1/charges');
req.setMethod('POST');
req.setHeader('Content-Type', 'application/x-www-form-urlencoded');
String body = 'amount=2500&currency=usd&source=tok_visa&description=Order+1234';
req.setBody(body);
HttpResponse res = new Http().send(req);
if (res.getStatusCode() == 200) {
    Map<String, Object> parsed = (Map<String, Object>) JSON.deserializeUntyped(res.getBody());
    String chargeId = (String) parsed.get('id');
    System.debug('Charge succeeded: ' + chargeId);
} else {
    System.debug('Charge failed: ' + res.getStatusCode() + ' - ' + res.getBody());
}
